import pygal
import cairosvg  # pip install cairosvg

# Generated by repeatedly running `for i in {1..10}; do ./bench; sleep 0.7; done`,
# where 0.7 is replaced by the durations in the below keys.
data = {
    "sleep 1.0": [2.49, 2.13, 2.23, 2.22, 2.25, 2.23, 2.28, 2.50, 2.29, 2.28],
    "sleep 0.9": [2.35, 2.29, 2.58, 2.18, 2.22, 2.25, 2.28, 2.21, 2.20, 2.20],
    "sleep 0.8": [2.53, 2.03, 2.24, 2.15, 2.23, 2.53, 2.19, 2.19, 2.20, 2.56],
    "sleep 0.7": [2.38, 2.17, 2.11, 2.11, 2.17, 2.36, 2.23, 2.11, 2.11, 1.97],
    "sleep 0.6": [2.45, 2.10, 2.07, 2.09, 2.15, 2.14, 2.02, 2.04, 1.97, 1.17],
    "sleep 0.5": [2.38, 2.02, 1.65, 1.26, 0.99, 1.00, 1.00, 0.99, 0.98, 1.01],
    "sleep 0.4": [2.33, 1.92, 1.05, 0.98, 1.00, 0.99, 0.98, 1.06, 1.00, 0.99],
    "sleep 0.3": [2.43, 1.85, 1.00, 1.00, 1.00, 0.98, 0.99, 1.00, 1.00, 1.01],
    "sleep 0.2": [2.39, 1.67, 1.03, 0.98, 1.00, 1.00, 0.98, 0.99, 0.99, 1.00],
    "sleep 0.1": [2.39, 1.44, 1.00, 0.99, 1.00, 0.99, 1.00, 0.99, 0.99, 0.99],
    "sleep 0.0": [2.47, 1.12, 1.00, 1.00, 0.99, 1.00, 0.99, 1.02, 0.99, 1.01],
}

chart = pygal.Line()
chart.title = "Run vs runtime, with different sleep durations"
chart.x_labels = [str(i) for i in range(1, 11)]
chart.x_title = "Run"
chart.y_title = "Seconds"

for label, values in data.items():
    chart.add(label, values)

svg_file = "benchmark.svg"
chart.render_to_file(svg_file)

cairosvg.svg2png(url=svg_file, write_to="benchmark.png")
